    if t == 1:
        return 'C'
    
    # Final round: Only cooperate if the previous round was a success
    if t == r:
        if history[-1] >= m:
            return 'C'
        else:
            return 'D'
    
    # Intermediate rounds: Reciprocate success, adjust to failure
    prev_cooperators = history[-1]
    
